package com.multilanglearner.ui.home

import android.app.Application
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.db.entity.VideoEntity
import com.multilanglearner.data.repository.VideoRepository
import com.multilanglearner.data.store.ThemeStore
import com.yausername.youtubedl_android.YoutubeDL
import com.yausername.youtubedl_android.YoutubeDLRequest
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import java.io.File
import javax.inject.Inject

data class HomeUiState(
    val url: String = "",
    val selectedLang: String = "en",
    val isDownloading: Boolean = false,
    val downloadProgress: Float = 0f,
    val statusText: String = "",
    val videos: List<VideoEntity> = emptyList()
)

@HiltViewModel
class HomeViewModel @Inject constructor(
    application: Application,
    private val videoRepository: VideoRepository,
    private val themeStore: ThemeStore
) : AndroidViewModel(application) {
    private val _uiState = MutableStateFlow(HomeUiState())
    val uiState: StateFlow<HomeUiState> = _uiState.asStateFlow()

    private val downloadsDir: File = File(application.filesDir, "downloads").also { it.mkdirs() }

    init {
        viewModelScope.launch {
            videoRepository.getAll().collect { videos ->
                _uiState.update { it.copy(videos = videos) }
            }
        }
    }

    fun setUrl(url: String) { _uiState.update { it.copy(url = url) } }
    fun setLang(lang: String) { _uiState.update { it.copy(selectedLang = lang) } }

    fun setTheme(theme: String) { viewModelScope.launch { themeStore.setTheme(theme) } }
    fun setFontSize(size: String) { viewModelScope.launch { themeStore.setFontSize(size) } }

    fun downloadVideo(onComplete: (String, String?) -> Unit) {
        val url = _uiState.value.url.trim()
        if (url.isBlank()) return

        _uiState.update { it.copy(isDownloading = true, downloadProgress = 0f, statusText = "正在下载...") }

        viewModelScope.launch(Dispatchers.IO) {
            try {
                val request = YoutubeDLRequest(url).apply {
                    addOption("-o", "${downloadsDir.absolutePath}/%(title)s.%(ext)s")
                    addOption("--write-sub")
                    addOption("--write-auto-sub")
                    addOption("--sub-lang", _uiState.value.selectedLang)
                    addOption("--sub-format", "vtt")
                    addOption("--convert-subs", "vtt")
                    addOption("-f", "bestvideo[height<=720]+bestaudio/best[height<=720]/best")
                    addOption("--merge-output-format", "mp4")
                    addOption("--no-playlist")
                }

                YoutubeDL.getInstance().execute(request) { progress, line ->
                    _uiState.update { it.copy(downloadProgress = progress / 100f, statusText = "下载中 ${progress.toInt()}%") }
                }

                // Find downloaded files
                val mp4Files = downloadsDir.listFiles { f -> f.extension == "mp4" }?.sortedByDescending { it.lastModified() }
                val videoFile = mp4Files?.firstOrNull()
                if (videoFile != null) {
                    val vttFile = downloadsDir.listFiles { f ->
                        f.nameWithoutExtension.startsWith(videoFile.nameWithoutExtension) && f.extension == "vtt"
                    }?.firstOrNull()

                    val entity = VideoEntity(
                        title = videoFile.nameWithoutExtension,
                        filePath = videoFile.absolutePath,
                        vttPath = vttFile?.absolutePath,
                        language = _uiState.value.selectedLang,
                        sourceUrl = url
                    )
                    videoRepository.insert(entity)

                    _uiState.update { it.copy(isDownloading = false, statusText = "下载完成!") }
                    launch(Dispatchers.Main) { onComplete(videoFile.absolutePath, vttFile?.absolutePath) }
                } else {
                    _uiState.update { it.copy(isDownloading = false, statusText = "下载失败") }
                }
            } catch (e: Exception) {
                _uiState.update { it.copy(isDownloading = false, statusText = "失败: ${e.message}") }
            }
        }
    }

    fun importVideo(onComplete: (String, String?) -> Unit) {
        // Import will be triggered via ActivityResult in the UI layer
        // This is a placeholder - actual file picking happens in the Composable
        _uiState.update { it.copy(statusText = "请选择视频文件") }
    }
}

package com.multilanglearner.ui.ai

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.multilanglearner.domain.model.AI_PROVIDERS

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AISettingsSheet(
    onDismiss: () -> Unit,
    viewModel: AISettingsViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()

    ModalBottomSheet(onDismissRequest = onDismiss) {
        Column(modifier = Modifier.padding(16.dp).fillMaxWidth()) {
            Text("⚙ AI 设置", style = MaterialTheme.typography.titleLarge)
            Text("AI 用于词汇释义、句子分析等功能", style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant)

            Spacer(Modifier.height(12.dp))

            // Provider selector
            var providerExpanded by remember { mutableStateOf(false) }
            ExposedDropdownMenuBox(expanded = providerExpanded, onExpandedChange = { providerExpanded = it }) {
                OutlinedTextField(
                    value = AI_PROVIDERS.find { it.id == uiState.provider }?.name ?: "",
                    onValueChange = {},
                    readOnly = true,
                    label = { Text("AI 服务商") },
                    modifier = Modifier.fillMaxWidth().menuAnchor(),
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(providerExpanded) }
                )
                ExposedDropdownMenu(expanded = providerExpanded, onDismissRequest = { providerExpanded = false }) {
                    AI_PROVIDERS.forEach { provider ->
                        DropdownMenuItem(
                            text = { Text(provider.name) },
                            onClick = { viewModel.setProvider(provider.id); providerExpanded = false }
                        )
                    }
                }
            }

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.apiKey, onValueChange = viewModel::setApiKey,
                label = { Text("API Key") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.baseUrl, onValueChange = viewModel::setBaseUrl,
                label = { Text("Base URL (可选)") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            OutlinedTextField(value = uiState.model, onValueChange = viewModel::setModel,
                label = { Text("模型名称 (可选)") }, modifier = Modifier.fillMaxWidth(), singleLine = true)

            Spacer(Modifier.height(8.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(value = uiState.maxTokens, onValueChange = viewModel::setMaxTokens,
                    label = { Text("Max Tokens") }, modifier = Modifier.weight(1f), singleLine = true)
                OutlinedTextField(value = uiState.temperature, onValueChange = viewModel::setTemperature,
                    label = { Text("Temperature") }, modifier = Modifier.weight(1f), singleLine = true)
            }

            HorizontalDivider(modifier = Modifier.padding(vertical = 12.dp))

            Text("语音转录设置", style = MaterialTheme.typography.titleSmall)
            Row(verticalAlignment = Alignment.CenterVertically) {
                Text("启用 Groq Whisper")
                Spacer(Modifier.weight(1f))
                Switch(checked = uiState.groqWhisperEnabled, onCheckedChange = viewModel::setGroqWhisper)
            }

            // Whisper model
            var whisperExpanded by remember { mutableStateOf(false) }
            ExposedDropdownMenuBox(expanded = whisperExpanded, onExpandedChange = { whisperExpanded = it }) {
                OutlinedTextField(
                    value = uiState.whisperModel, onValueChange = {},
                    readOnly = true, label = { Text("Whisper 模型") },
                    modifier = Modifier.fillMaxWidth().menuAnchor(),
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(whisperExpanded) }
                )
                ExposedDropdownMenu(expanded = whisperExpanded, onDismissRequest = { whisperExpanded = false }) {
                    listOf("whisper-large-v3", "whisper-large-v3-turbo").forEach { model ->
                        DropdownMenuItem(text = { Text(model) },
                            onClick = { viewModel.setWhisperModel(model); whisperExpanded = false })
                    }
                }
            }

            HorizontalDivider(modifier = Modifier.padding(vertical = 12.dp))

            // Subtitle translate mode
            Text("字幕翻译设置", style = MaterialTheme.typography.titleSmall)
            var transExpanded by remember { mutableStateOf(false) }
            ExposedDropdownMenuBox(expanded = transExpanded, onExpandedChange = { transExpanded = it }) {
                OutlinedTextField(
                    value = when (uiState.subtitleTranslateMode) {
                        "none" -> "不翻译（保持原语种）"
                        "ai" -> "AI 大模型翻译"
                        "baidu" -> "百度翻译"
                        else -> uiState.subtitleTranslateMode
                    },
                    onValueChange = {}, readOnly = true,
                    label = { Text("字幕翻译方式") },
                    modifier = Modifier.fillMaxWidth().menuAnchor(),
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(transExpanded) }
                )
                ExposedDropdownMenu(expanded = transExpanded, onDismissRequest = { transExpanded = false }) {
                    listOf("none" to "不翻译", "ai" to "AI 大模型翻译", "baidu" to "百度翻译").forEach { (value, label) ->
                        DropdownMenuItem(text = { Text(label) },
                            onClick = { viewModel.setTranslateMode(value); transExpanded = false })
                    }
                }
            }

            Spacer(Modifier.height(16.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                Button(onClick = { viewModel.save(); onDismiss() }, modifier = Modifier.weight(1f)) { Text("保存") }
                OutlinedButton(onClick = { viewModel.testConnection() }, modifier = Modifier.weight(1f)) { Text("🔗 测试") }
            }

            if (uiState.testResult.isNotBlank()) {
                Spacer(Modifier.height(8.dp))
                Text(uiState.testResult, style = MaterialTheme.typography.bodySmall,
                    color = if (uiState.testSuccess) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.error)
            }

            Spacer(Modifier.height(32.dp))
        }
    }
}

